import React, { useEffect, useRef } from 'react';

const VirtualKeyboard = ({ activeKey, onKeyPress, isCorrect }) => {
  const correctSoundRef = useRef(null);
  const wrongSoundRef = useRef(null);
  const lastKeyRef = useRef(null);

  // Finger mapping for highlighting
  const fingerMap = {
    // Left hand
    'q': 'left-pinky', 'a': 'left-pinky', 'z': 'left-pinky', '1': 'left-pinky',
    'w': 'left-ring', 's': 'left-ring', 'x': 'left-ring', '2': 'left-ring',
    'e': 'left-middle', 'd': 'left-middle', 'c': 'left-middle', '3': 'left-middle',
    'r': 'left-index', 'f': 'left-index', 'v': 'left-index', 't': 'left-index', 'g': 'left-index', 'b': 'left-index', '4': 'left-index', '5': 'left-index',

    // Right hand
    'y': 'right-index', 'h': 'right-index', 'n': 'right-index', 'u': 'right-index', 'j': 'right-index', 'm': 'right-index', '6': 'right-index', '7': 'right-index',
    'i': 'right-middle', 'k': 'right-middle', ',': 'right-middle', '8': 'right-middle',
    'o': 'right-ring', 'l': 'right-ring', '.': 'right-ring', '9': 'right-ring',
    'p': 'right-pinky', ';': 'right-pinky', "'": 'right-pinky', '/': 'right-pinky', '0': 'right-pinky', '-': 'right-pinky', '=': 'right-pinky', '[': 'right-pinky', ']': 'right-pinky',

    ' ': 'thumbs'
  };

  const keyboardLayout = [
    ['1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
    ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
    ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', "'"],
    ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/'],
    ['SPACE']
  ];

  // Create audio feedback sounds
  useEffect(() => {
    // Correct key sound (800Hz, pleasant)
    const correctAudioContext = new (window.AudioContext || window.webkitAudioContext)();
    const correctOscillator = correctAudioContext.createOscillator();
    const correctGain = correctAudioContext.createGain();

    correctOscillator.connect(correctGain);
    correctGain.connect(correctAudioContext.destination);

    correctOscillator.frequency.value = 800;
    correctOscillator.type = 'sine';
    correctGain.gain.value = 0;

    correctOscillator.start();
    correctSoundRef.current = { context: correctAudioContext, oscillator: correctOscillator, gain: correctGain };

    // Wrong key sound (400Hz, lower)
    const wrongAudioContext = new (window.AudioContext || window.webkitAudioContext)();
    const wrongOscillator = wrongAudioContext.createOscillator();
    const wrongGain = wrongAudioContext.createGain();

    wrongOscillator.connect(wrongGain);
    wrongGain.connect(wrongAudioContext.destination);

    wrongOscillator.frequency.value = 400;
    wrongOscillator.type = 'sine';
    wrongGain.gain.value = 0;

    wrongOscillator.start();
    wrongSoundRef.current = { context: wrongAudioContext, oscillator: wrongOscillator, gain: wrongGain };

    return () => {
      if (correctSoundRef.current) {
        correctSoundRef.current.oscillator.stop();
        correctSoundRef.current.context.close();
      }
      if (wrongSoundRef.current) {
        wrongSoundRef.current.oscillator.stop();
        wrongSoundRef.current.context.close();
      }
    };
  }, []);

  // Play sound when key is pressed
  useEffect(() => {
    if (activeKey && lastKeyRef.current !== activeKey) {
      lastKeyRef.current = activeKey;

      if (isCorrect !== undefined) {
        if (isCorrect) {
          playCorrectSound();
        } else {
          playWrongSound();
        }
      }
    }
  }, [activeKey, isCorrect]);

  const playCorrectSound = () => {
    if (correctSoundRef.current) {
      const { gain, context } = correctSoundRef.current;
      const now = context.currentTime;

      gain.gain.cancelScheduledValues(now);
      gain.gain.setValueAtTime(0.2, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.05);
    }
  };

  const playWrongSound = () => {
    if (wrongSoundRef.current) {
      const { gain, context } = wrongSoundRef.current;
      const now = context.currentTime;

      gain.gain.cancelScheduledValues(now);
      gain.gain.setValueAtTime(0.15, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.08);
    }
  };

  const isKeyActive = (key) => {
    if (!activeKey) return false;

    if (key === 'SPACE' && activeKey === ' ') return true;

    return key.toLowerCase() === activeKey.toLowerCase();
  };

  const getFingerClass = (key) => {
    const normalizedKey = key === 'SPACE' ? ' ' : key.toLowerCase();
    return fingerMap[normalizedKey] || '';
  };

  const getCurrentFinger = () => {
    if (!activeKey) return '';
    const normalizedKey = activeKey === ' ' ? ' ' : activeKey.toLowerCase();
    return fingerMap[normalizedKey] || '';
  };

  const currentFinger = getCurrentFinger();

  return (
    <div className="virtual-keyboard">
      {keyboardLayout.map((row, rowIndex) => (
        <div key={rowIndex} className="keyboard-row">
          {row.map((key) => {
            const fingerClass = getFingerClass(key);
            const isActive = isKeyActive(key);
            const shouldGlow = currentFinger && fingerClass === currentFinger;

            return (
              <div
                key={key}
                className={`key ${key === 'SPACE' ? 'space' : ''} ${
                  isActive ? 'active' : ''
                } ${shouldGlow ? 'finger-glow' : ''} ${fingerClass}`}
              >
                {key === 'SPACE' ? 'Space' : key}
              </div>
            );
          })}
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '0.75rem', color: '#666', fontSize: '0.85rem' }}>
        <p>Keep your fingers on the home row: A S D F | J K L ;</p>
      </div>
    </div>
  );
};

export default VirtualKeyboard;
